var messages={messages:null,init:function(){messages.showMessages()},showMessages:function(){$.ajax({url:"/messages/ajax",type:"post",dataType:"json",data:{action:"get_messages"},success:function(a){messages.messages=a.messages;if(a.success){$("#i_div_messages_container").html(a.html)}},error:function(){}})},showMessageDetail:function(a){var b=$(a).data("messageId");for(i in messages.messages){if(messages.messages[i].messageUserId==b){$("#i_dialog_container_label").html("Текст уведомления");$("#i_dialog_container_container").html(messages.messages[i].text)}}$("#i_dialog_container").modal("show")},hideMessage:function(a){var b=$(a).data("messageId");$("#i_li_"+b).remove();$.ajax({url:"/messages/ajax",type:"post",dataType:"json",data:{action:"removeMessage",messageUserId:b},success:function(c){messages.showMessages()},error:function(){messages.showMessages()}})}};$(document).ready(function(){messages.init()});